insert into changer_rules (icon, name, rule, action) values
  ('⚡', 'SPEED ROUND', 'Le premier à taper sur la table après chaque question marque 1 pt. Si tu te trompes de réponse, tu perds 2 pts !', 'Posez-vous des questions de culture générale.'),
  ('🤫', 'CHUCHOTEUR', 'TOUT LE MONDE doit chuchoter. Parler normalement = −1 pt. Le dernier à parler fort est éliminé.', 'Continuez à jouer normalement mais en chuchotant.'),
  ('🔄', 'MIROIR', 'Tout ce qu''un joueur fait, son voisin de gauche doit l''imiter exactement. Rater = −1 pt.', 'Essayez de piéger votre voisin avec des gestes compliqués.'),
  ('🎭', 'INTERDIT DE RIRE', 'Personne ne doit sourire. Le premier qui rit donne 3 pts à tous les autres. Durée : 2 minutes.', 'Essayez de faire rire les autres sans sourire vous-même.'),
  ('📱', 'SANS LES MAINS', 'Vous ne pouvez pas utiliser vos mains. Utiliser ses mains = −2 pts.', 'Accomplissez des défis sans utiliser vos mains.'),
  ('🔢', 'CHIFFRES INTERDITS', 'Remplacez tous les chiffres par "BZZZ". Dire un chiffre = −1 pt. Durée : 3 minutes.', 'Discutez normalement en censurant chaque chiffre.'),
  ('🎤', 'MICRO OUVERT', 'Tout ce que tu penses, tu dois le dire à voix haute. Rester silencieux = −1 pt.', 'Chaque pensée doit être vocalisée !'),
  ('🕺', 'DANSE OBLIGATOIRE', 'À chaque fois qu''on dit le mot "je", tout le monde doit danser 3 secondes. Oublier = −1 pt.', 'Discutez normalement en surveillant le mot "je".');
